  border-radius: 50%;
  background: transparent;
  cursor: pointer;
  opacity: 0.5;
  transition: opacity 120ms var(--ease-out), background-color 120ms var(--ease-out);
}

.p-presentation__dot:hover {
  opacity: 0.85;
}

.p-presentation__dot--active {
  background: currentcolor;
  opacity: 1;
}

.p-presentation__heading:focus {
  outline: none;
}

.p-presentation__nav {
  display: flex;
  align-items: center;
  gap: var(--s-3);
}

.p-presentation__nav-btn {
  flex: 1 1 0;
