  .p-presentation {
    padding: var(--s-5) !important;
  }

  .p-presentation__dot {
    width: 12px;
    height: 12px;
  }
}

@media (prefers-reduced-motion: reduce) {
  .p-presentation__phase,
  .p-presentation__phase--out {
    transition: none;
  }
}

